  ('dietitian-moex-09680', 'dietitian', 'dietitian-moex-096-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列那種賀爾蒙與骨骼的生長最不相關？', '["甲狀腺素", "性賀爾蒙", "糖皮質素（cortisol）", "礦皮質素（aldosterone）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:54+00:00", "source_pdf_sha1": "2165ea180c34", "answer_pdf_sha1": "43829f5695ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "096040", "c": "112", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "096", "exam_name": "096年第一次專技醫事人員、中醫、心理、呼吸治療、營養師、獸醫人員考試暨醫師分試考試第一試", "original_question_number": 13, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
